import { createClient } from '@supabase/supabase-js'
import { NextResponse } from 'next/server'
export const dynamic = 'force-dynamic'
export const maxDuration = 60
const PIZZA_B64 = ``
const FLAVORS = [
  { name: 'Pizza Calabresa', desc: 'Calabresa fatiada, cebola e molho de tomate', sizes: [{name:'Broto',price:35},{name:'Grande',price:60}] },
  { name: 'Pizza Quatro Queijos', desc: 'Mussarela, provolone, parmesão e gorgonzola', sizes: [{name:'Broto',price:45},{name:'Grande',price:80}] },
  { name: 'Pizza Portuguesa', desc: 'Presunto, ovo, cebola, ervilha e mussarela', sizes: [{name:'Broto',price:40},{name:'Grande',price:70}] },
  { name: 'Pizza Frango c/ Catupiry', desc: 'Frango desfiado com catupiry cremoso', sizes: [{name:'Broto',price:42},{name:'Grande',price:75}] },
]
export async function GET(req: Request) {
  const url = new URL(req.url)
  if (url.searchParams.get('secret') !== 'turbo-seed-2026') return NextResponse.json({ error: 'unauthorized' }, { status: 401 })
  const supabase = createClient(process.env.NEXT_PUBLIC_SUPABASE_URL!, process.env.SUPABASE_SERVICE_ROLE_KEY!)
  const { data: biz } = await supabase.from('businesses').select('id').eq('slug', 'dogao-do-denis-ikir').single()
  if (!biz) return NextResponse.json({ error: 'business not found' }, { status: 404 })

  if (url.searchParams.get('clean') === '1') {
    await supabase.from('products').delete().eq('business_id', biz.id).like('name', 'Pizza %')
    await supabase.from('categories').delete().eq('business_id', biz.id).eq('name', 'Pizzas')
    return NextResponse.json({ ok: true, cleaned: true })
  }

  // upload pizza image
  await supabase.storage.createBucket('menu', { public: true }).catch(()=>{})
  const buffer = Buffer.from(PIZZA_B64, 'base64')
  await supabase.storage.from('menu').upload(`${biz.id}/pizza.jpg`, buffer, { contentType: 'image/jpeg', upsert: true })
  const imgUrl = supabase.storage.from('menu').getPublicUrl(`${biz.id}/pizza.jpg`).data.publicUrl

  // category Pizzas (remove old, recreate)
  await supabase.from('products').delete().eq('business_id', biz.id).like('name', 'Pizza %')
  await supabase.from('categories').delete().eq('business_id', biz.id).eq('name', 'Pizzas')
  const { data: cat } = await supabase.from('categories').insert({ business_id: biz.id, name: 'Pizzas', icon: '🍕', sort_order: 0, is_active: true }).select('id').single()

  let n = 0
  for (const f of FLAVORS) {
    await supabase.from('products').insert({
      business_id: biz.id, category_id: cat?.id ?? null,
      name: f.name, description: f.desc, price: Math.min(...f.sizes.map(s=>s.price)),
      image_url: imgUrl, is_available: true, is_featured: false, is_combo: false,
      sort_order: n, views: 0, orders: 0,
      pizza: { sizes: f.sizes, maxFlavors: 2 },
    })
    n++
  }
  return NextResponse.json({ ok: true, flavors: n })
}
